ang=\"SV\" style=\"font-size: 11pt; line-height: 15.6933px; font-family: Calibri, sans-serif; position: relative; top: 3.5pt;\"><v:shapetype id=\"_x0000_t75\" coordsize=\"21600,21600\" o:spt=\"75\" o:preferrelative=\"t\" path=\"m@4@5l@4@11@9@11@9@5xe\" filled=\"f\" stroked=\"f\"><v:stroke joinstyle=\"miter\"><v:formulas><v:f eqn=\"if lineDrawn pixelLineWidth 0\"><v:f eqn=\"sum @0 1 0\"><v:f eqn=\"sum 0 0 @1\"><v:f eqn=\"prod @2 1 2\"><v:f eqn=\"prod @3 21600 pixelWidth\"><v:f eqn=\"prod @3 21600 pixelHeight\"><v:f eqn=\"sum @0 0 1\"><v:f eqn=\"prod @6 1 2\"><v:f eqn=\"prod @7 21600 pixelWidth\"><v:f eqn=\"sum @8 21600 0\"><v:f eqn=\"prod @7 21600 pixelHeight\"><v:f eqn=\"sum @10 21600 0\"></v:f></v:f></v:f></v:f></v:f></v:f></v:f></v:f></v:f></v:f></v:f></v:f></v:formulas><v:path o:extrusionok=\"f\" gradientshapeok=\"t\" o:connecttype=\"rect\"><o:lock v:ext=\"edit\" aspectratio=\"t\"></o:lock></v:path></v:stroke></v:shapetype><v:shape id=\"_x0000_i1025\" type=\"#_x0000_t75\" style=\"width: 7pt; height: 15pt;\"><v:imagedata src=\"file:///C:/Users/Lenovo/AppData/Local/Temp/msohtmlclip1/01/clip_image001.png\" o:title=\"\" chromakey=\"white\"></v:imagedata></v:shape></span><span style=\"font-size: 12pt; line-height: 17.12px; font-family: &quot;Times New Roman&quot;, serif;\">&nbsp;</span><span lang=\"SV\" style=\"font-size: 12pt; line-height: 17.12px; font-family: &quot;Times New Roman&quot;, serif;\">sebesar 15% memberikan peningkatan energi lebih besar karena kontribusi my<sup>2</sup></span><span lang=\"SV\" style=\"font-size: 11pt; line-height: 15.6933px; font-family: Calibri, sans-serif; position: relative; top: 3.5pt;\"><v:shape id=\"_x0000_i1025\" type=\"#_x0000_t75\" style=\"width: 23pt; height: 15.5pt;\"><v:imagedata src=\"file:///C:/Users/Lenovo/AppData/Local/Temp/msohtmlclip1/01/clip_image002.png\" o:title=\"\" chromakey=\"white\"></v:imagedata></v:shape></span><span style=\"font-size: 12pt; line-height: 17.12px; font-family: &quot;Times New Roman&quot;, serif;\">&nbsp;</span><span lang=\"SV\" style=\"font-size: 12pt; line-height: 17.12px; font-family: &quot;Times New Roman&quot;, serif;\">terhadap momen inersia lebih dominan</span></p>', NULL, 'E', 0.520, 0, 1, '2026-05-03 16:46:18', '2026-05-03 16:46:18'),
(368, 'ACTofROD26', 11, NULL, '<p><span lang=\"IN\" style=\"font-size:12.0pt;line-height:\r\n107%;font-family:&quot;Times New Roman&quot;,serif;mso-ascii-theme-font:major-bidi;\r\nmso-fareast-font-family:Calibri;mso-fareast-theme-font:minor-latin;mso-hansi-theme-font:\r\nmajor-bidi;mso-bidi-theme-font:major-bidi;mso-ansi-language:IN;mso-fareast-language:\r\nEN-US;mso-bidi-language:AR-SA\">Perhatikan gambar 25 menunjukkan baling-baling\r\ndipasang di tengah meja putar.</span></p><p><img src=\"https://cd-cat.ct.ws/uploads/editor-images/editor_1777763830_69f685f61b5fb.png\" class=\"img-fluid\" style=\"display: block; max-width: 100%; height: 132.967px; margin: 10px 0px; width: 333.896px;\"></p><p class=\"MsoNormal\" align=\"center\" style=\"text-align:center;line-height:150%\"><span lang=\"IN\" style=\"font-size:12.0pt;line-height:150%;font-family:&quot;Times New Roman&quot;,serif;\r\nmso-ascii-theme-font:major-bidi;mso-hansi-theme-font:major-bidi;mso-bidi-theme-font:\r\nmajor-bidi\">Gambar 25. Baling-baling pada meja putar<o:p></o:p></span></p><p><span lang=\"IN\" style=\"font-size:12.0pt;line-height:\r\n107%;font-family:&quot;Times New Roman&quot;,serif;mso-ascii-theme-font:major-bidi;\r\nmso-fareast-font-family:Calibri;mso-fareast-theme-font:minor-latin;mso-hansi-theme-font:\r\nmajor-bidi;mso-bidi-theme-font:major-bidi;mso-ansi-language:IN;mso-fareast-language:\r\nEN-US;mso-bidi-language:AR-SA\">\r\n\r\n<span lang=\"IN\" style=\"font-size: 12pt; line-height: 107%;\">Baling-baling\r\ndan meja putar memiliki sumbu rotasi yang sama dan digerakkan oleh motor\r\nbaterai. Awalnya dalam keadaan diam, kemudian motor dihidupkan dan\r\nbaling-baling dengan cepat berputar mencapai kecepatan sudut akhir yang tinggi\r\ndan berputar searah jarum jam jika dilihat dari atas. Dengan menggunakan konsep\r\nkekekalan momentum sudut, gerakan meja putar dibandingkan dengan baling-baling\r\nadalah....</span></span></p>', '<p><span lang=\"IN\" style=\"font-size:12.0pt;line-height:\r\n107%;font-family:&quot;Times New Roman&quot;,serif;mso-ascii-theme-font:major-bidi;\r\nmso-fareast-font-family:Calibri;mso-fareast-theme-font:minor-latin;mso-hansi-theme-font:\r\nmajor-bidi;mso-bidi-theme-font:major-bidi;mso-ansi-language:IN;mso-fareast-language:\r\nEN-US;mso-bidi-language:AR-SA\">meja putar berputar searah jarum jam, sama\r\nseperti baling-baling, karena keduanya memiliki satu sumber motor yang sama</span></p>', '<p><span lang=\"IN\" style=\"font-size:12.0pt;line-height:\r\n107%;font-family:&quot;Times New Roman&quot;,serif;mso-ascii-theme-font:major-bidi;\r\nmso-fareast-font-family:Calibri;mso-fareast-theme-font:minor-latin;mso-hansi-theme-font:\r\nmajor-bidi;mso-bidi-theme-font:major-bidi;mso-ansi-language:IN;mso-fareast-language:\r\nEN-US;mso-bidi-language:AR-SA\">meja putar tidak bergerak karena motor hanya\r\nmemberikan torsi pada baling-baling, bukan pada meja putar</span></p>', '<p><span lang=\"IN\" style=\"font-size:12.0pt;line-height:\r\n107%;font-family:&quot;Times New Roman&quot;,serif;mso-ascii-theme-font:major-bidi;\r\nmso-fareast-font-family:Calibri;mso-fareast-theme-font:minor-latin;mso-hansi-theme-font:\r\nmajor-bidi;mso-bidi-theme-font:major-bidi;mso-ansi-language:IN;mso-fareast-language:\r\nEN-US;mso-bidi-language:AR-SA\">meja putar berputar berlawanan arah jarum jam\r\nkarena momentum sudut total sistem harus tetap nol</span></p>', '<p><span lang=\"IN\" style=\"font-size:12.0pt;line-height:\r\n107%;font-family:&quot;Times New Roman&quot;,serif;mso-ascii-theme-font:major-bidi;\r\nmso-fareast-font-family:Calibri;mso-fareast-theme-font:minor-latin;mso-hansi-theme-font:\r\nmajor-bidi;mso-bidi-theme-font:major-bidi;mso-ansi-language:IN;mso-fareast-language:\r\nEN-US;mso-bidi-language:AR-SA\">meja putar akan berputar acak tergantung besar\r\ngesekan bantalan, tidak terkait arah baling-baling</span></p>', '<p><span lang=\"IN\" style=\"font-size:12.0pt;line-height:\r\n107%;font-family:&quot;Times New Roman&quot;,serif;mso-ascii-theme-font:major-bidi;\r\nmso-fareast-font-family:Calibri;mso-fareast-theme-font:minor-latin;mso-hansi-theme-font:\r\nmajor-bidi;mso-bidi-theme-font:major-bidi;mso-ansi-language:IN;mso-fareast-language:\r\nEN-US;mso-bidi-language:AR-SA\">meja putar hanya bergoyang tanpa rotasi karena\r\nmotor tidak menempel pada meja putar</span></p>', '<p><span lang=\"IN\" style=\"font-size:12.0pt;line-height:\r\n107%;font-family:&quot;Times New Roman&quot;,serif;mso-ascii-theme-font:major-bidi;\r\nmso-fareast-font-family:Calibri;mso-fareast-theme-font:minor-latin;mso-hansi-theme-font:\r\nmajor-bidi;mso-bidi-theme-font:major-bidi;mso-ansi-language:IN;mso-fareast-language:\r\nEN-US;mso-bidi-language:AR-SA\">meja putar berputar berlawanan arah jarum jam\r\nkarena momentum sudut total sistem harus tetap nol</span></p>', NULL, 'C', 0.180, 0, 1, '2026-05-03 16:46:18', '2026-05-03 16:46:18');
INSERT INTO `soal_ujian` (`soal_id`, `kode_soal`, `ujian_id`, `bank_ujian_id`, `pertanyaan`, `pilihan_a`, `pilihan_b`, `pilihan_c`, `pilihan_d`, `pilihan_e`, `pembahasan`, `foto`, `jawaban_benar`, `tingkat_kesulitan`, `is_bank_soal`, `created_by`, `created_at`, `updated_at`) VALUES
(369, 'ACTofROD25', 11, NULL, '<p><span lang=\"IN\" style=\"font-size:12.0pt;line-height:\r\n107%;font-family:&quot;Times New Roman&quot;,serif;mso-ascii-theme-font:major-bidi;\r\nmso-fareast-font-family:Calibri;mso-fareast-theme-font:minor-latin;mso-hansi-theme-font:\r\nmajor-bidi;mso-bidi-theme-font:major-bidi;mso-ansi-language:IN;mso-fareast-language:\r\nEN-US;mso-bidi-language:AR-SA\">Seorang atlet senam turun dari gerakan di mana\r\nia berayun di atas palang tinggi. Atlet senam berputar di udara sebelum\r\nmendarat. Gambar &nbsp;24 menunjukkan atlet\r\nsenam dalam tiga posisi selama proses turun.</span></p><ul><li><img src=\"https://cd-cat.ct.ws/uploads/editor-images/editor_1777763501_69f684ad6b232.png\" class=\"img-fluid\" style=\"display: block; max-width: 100%; height: 195.709px; margin: 10px 0px; width: 297.104px;\"><span lang=\"IN\" style=\"font-size:12.0pt;line-height:\r\n107%;font-family:&quot;Times New Roman&quot;,serif;mso-ascii-theme-font:major-bidi;\r\nmso-fareast-font-family:Calibri;mso-fareast-theme-font:minor-latin;mso-hansi-theme-font:\r\nmajor-bidi;mso-bidi-theme-font:major-bidi;mso-ansi-language:IN;mso-fareast-language:\r\nEN-US;mso-bidi-language:AR-SA\"><span lang=\"IN\" style=\"font-size: 12pt; line-height: 107%;\">Posisi 1, atlet senam baru melepaskan\r\npegangannya dari palang. Tubuhnya dalam posisi terentang sepenuhnya</span></span></li><li><span lang=\"IN\" style=\"font-size:12.0pt;line-height:\r\n107%;font-family:&quot;Times New Roman&quot;,serif;mso-ascii-theme-font:major-bidi;\r\nmso-fareast-font-family:Calibri;mso-fareast-theme-font:minor-latin;mso-hansi-theme-font:\r\nmajor-bidi;mso-bidi-theme-font:major-bidi;mso-ansi-language:IN;mso-fareast-language:\r\nEN-US;mso-bidi-language:AR-SA\"><span lang=\"IN\" style=\"font-size: 12pt; line-height: 107%;\"><span lang=\"IN\" style=\"font-size: 12pt; line-height: 107%;\">Posisi 2, atlet senam berputar beberapa saat\r\nkemudian. Lututnya telah didekatkan ke dada dalam posisi meringkuk</span></span></span></li><li><span lang=\"IN\" style=\"font-size:12.0pt;line-height:\r\n107%;font-family:&quot;Times New Roman&quot;,serif;mso-ascii-theme-font:major-bidi;\r\nmso-fareast-font-family:Calibri;mso-fareast-theme-font:minor-latin;mso-hansi-theme-font:\r\nmajor-bidi;mso-bidi-theme-font:major-bidi;mso-ansi-language:IN;mso-fareast-language:\r\nEN-US;mso-bidi-language:AR-SA\"><span lang=\"IN\" style=\"font-size: 12pt; line-height: 107%;\"><span lang=\"IN\" style=\"font-size: 12pt; line-height: 107%;\"><span lang=\"IN\" style=\"font-size: 12pt; line-height: 107%;\">Posisi 3, berada di akhir gerakan pendaratan\r\nsaat pesenam mendarat di matras. Tubuhnya kembali berdiri sepenuhnya</span></span></span></span></li></ul><p><span lang=\"IN\" style=\"font-size:12.0pt;line-height:\r\n107%;font-family:&quot;Times New Roman&quot;,serif;mso-ascii-theme-font:major-bidi;\r\nmso-fareast-font-family:Calibri;mso-fareast-theme-font:minor-latin;mso-hansi-theme-font:\r\nmajor-bidi;mso-bidi-theme-font:major-bidi;mso-ansi-language:IN;mso-fareast-language:\r\nEN-US;mso-bidi-language:AR-SA\"><span lang=\"IN\" style=\"font-size: 12pt; line-height: 107%;\">Mengapa momen inersia terhadap sumbu rotasi\r\nberkurang ketika lututnya di gerakan ke arah dada dan pengaruh terhadap\r\nkecepatan sudut adalah....</span></span></p>', '<p><span lang=\"IN\" style=\"font-size:12.0pt;line-height:\r\n107%;font-family:&quot;Times New Roman&quot;,serif;mso-ascii-theme-font:major-bidi;\r\nmso-fareast-font-family:Calibri;mso-fareast-theme-font:minor-latin;mso-hansi-theme-font:\r\nmajor-bidi;mso-bidi-theme-font:major-bidi;mso-ansi-language:IN;mso-fareast-language:\r\nEN-US;mso-bidi-language:AR-SA\">momen inersia berkurang karena tinggi pesenam\r\nterhadap sumbu rotasi berkurang sehingga kecepatan sudut mengalami peningkatan</span></p>', '<p><span lang=\"IN\" style=\"font-size:12.0pt;line-height:\r\n107%;font-family:&quot;Times New Roman&quot;,serif;mso-ascii-theme-font:major-bidi;\r\nmso-fareast-font-family:Calibri;mso-fareast-theme-font:minor-latin;mso-hansi-theme-font:\r\nmajor-bidi;mso-bidi-theme-font:major-bidi;mso-ansi-language:IN;mso-fareast-language:\r\nEN-US;mso-bidi-language:AR-SA\">momen inersia berkurang karena distribusi&nbsp; masa pesenam berada lebih dekat ke sumbu\r\nrotasi sehingga kecepatan sudut mengalami peningkatan&nbsp;</span></p>', '<p><span lang=\"IN\" style=\"font-size:12.0pt;line-height:\r\n107%;font-family:&quot;Times New Roman&quot;,serif;mso-ascii-theme-font:major-bidi;\r\nmso-fareast-font-family:Calibri;mso-fareast-theme-font:minor-latin;mso-hansi-theme-font:\r\nmajor-bidi;mso-bidi-theme-font:major-bidi;mso-ansi-language:IN;mso-fareast-language:\r\nEN-US;mso-bidi-language:AR-SA\">momen inersia berkurang karena tinggi pesenam\r\nterhadap sumbu rotasi berkurang dan distribusi massa lebih dekat ke sumbu\r\nrotasi sehingga kecepatan sudut mengalami penurunan&nbsp;</span></p>', '<p><span lang=\"IN\" style=\"font-size:12.0pt;line-height:\r\n107%;font-family:&quot;Times New Roman&quot;,serif;mso-ascii-theme-font:major-bidi;\r\nmso-fareast-font-family:Calibri;mso-fareast-theme-font:minor-latin;mso-hansi-theme-font:\r\nmajor-bidi;mso-bidi-theme-font:major-bidi;mso-ansi-language:IN;mso-fareast-language:\r\nEN-US;mso-bidi-language:AR-SA\">momen inersia berkurang karena tinggi pesenam\r\nterhadap sumbu rotasi berkurang dan distribusi massa lebih dekat ke sumbu\r\nrotasi sehingga kecepatan sudut mengalami peningkatan&nbsp;</span></p>', '<p><span lang=\"IN\" style=\"font-size:12.0pt;line-height:\r\n107%;font-family:&quot;Times New Roman&quot;,serif;mso-ascii-theme-font:major-bidi;\r\nmso-fareast-font-family:Calibri;mso-fareast-theme-font:minor-latin;mso-hansi-theme-font:\r\nmajor-bidi;mso-bidi-theme-font:major-bidi;mso-ansi-language:IN;mso-fareast-language:\r\nEN-US;mso-bidi-language:AR-SA\">momen inersia berkurang karena tinggi pesenam\r\nterhadap sumbu rotasi berkurang dan distribusi massa lebih dekat ke sumbu\r\nrotasi sehingga kecepatan sudut tetap sama karena tidak ada torsi eksternal</span></p>', '<p><span style=\"font-family: &quot;Times New Roman&quot;, serif;\">momen inersia berkurang karena tinggi pesenam terhadap sumbu rotasi berkurang dan distribusi massa lebih dekat ke sumbu rotasi sehingga kecepatan sudut mengalami peningkatan&nbsp;</span></p>', NULL, 'D', 0.310, 0, 1, '2026-05-03 16:46:18', '2026-05-03 16:46:18'),
(370, 'ACTofROD24', 11, NULL, '<p><span lang=\"IN\" style=\"font-size:12.0pt;line-height:\r\n107%;font-family:&quot;Times New Roman&quot;,serif;mso-ascii-theme-font:major-bidi;\r\nmso-fareast-font-family:Calibri;mso-fareast-theme-font:minor-latin;mso-hansi-theme-font:\r\nmajor-bidi;mso-bidi-theme-font:major-bidi;mso-ansi-language:IN;mso-fareast-language:\r\nEN-US;mso-bidi-language:AR-SA\">Gambar 23 menunjukkan grafik kecepatan sudut ω\r\nterhadap waktu t untuk sebuah benda yang diputar di sekitar sumbu rotasi.\r\nKecepatan sudut meningkat dari t = 0 hingga t = 3 s, lalu menurun hingga\r\nberhenti pada t = 6 s. Torsi bernilai positif jika putarannya searah jarum jam.</span></p><p><img src=\"https://cd-cat.ct.ws/uploads/editor-images/editor_1777763325_69f683fdab916.png\" class=\"img-fluid\" style=\"display: block; max-width: 100%; height: 119.027px; margin: 10px 0px; width: 345.104px;\"></p><p class=\"MsoNormal\" align=\"center\" style=\"text-align:center;line-height:150%\"><span lang=\"SV\" style=\"font-size:12.0pt;line-height:150%;font-family:&quot;Times New Roman&quot;,serif;\r\nmso-ascii-theme-font:major-bidi;mso-hansi-theme-font:major-bidi;mso-bidi-theme-font:\r\nmajor-bidi;mso-ansi-language:SV\">Gambar 23. Grafik kecepatan sudut terhadap\r\nwaktu</span></p><p><span lang=\"IN\" style=\"font-size:12.0pt;line-height:\r\n107%;font-family:&quot;Times New Roman&quot;,serif;mso-ascii-theme-font:major-bidi;\r\nmso-fareast-font-family:Calibri;mso-fareast-theme-font:minor-latin;mso-hansi-theme-font:\r\nmajor-bidi;mso-bidi-theme-font:major-bidi;mso-ansi-language:IN;mso-fareast-language:\r\nEN-US;mso-bidi-language:AR-SA\">\r\n\r\n\r\n\r\n<strong><span lang=\"IN\" style=\"font-size:11.0pt;line-height:107%;mso-ascii-font-family:\r\n&quot;Times New Roman&quot;;mso-ascii-theme-font:major-bidi;mso-fareast-font-family:&quot;Times New Roman&quot;;\r\nmso-fareast-theme-font:major-fareast;mso-hansi-font-family:&quot;Times New Roman&quot;;\r\nmso-hansi-theme-font:major-bidi;mso-bidi-font-family:&quot;Times New Roman&quot;;\r\nmso-bidi-theme-font:major-bidi;mso-ansi-language:IN;mso-fareast-language:EN-US;\r\nmso-bidi-language:AR-SA;font-weight:normal\">Berdasarkan grafik tersebut,\r\npernyataan yang paling tepat mengenai torsi yang bekerja pada benda adalah....</span></strong></span></p>', '<p><span lang=\"IN\" style=\"font-size:11.0pt;line-height:\r\n107%;font-family:&quot;Times New Roman&quot;,serif;mso-ascii-theme-font:major-bidi;\r\nmso-fareast-font-family:Calibri;mso-fareast-theme-font:minor-latin;mso-hansi-theme-font:\r\nmajor-bidi;mso-bidi-theme-font:major-bidi;mso-ansi-language:IN;mso-fareast-language:\r\nEN-US;mso-bidi-language:AR-SA\">torsi bernilai positif dari t = 0 hingga t = 3 s\r\nkarena ω meningkat, dan torsi bernilai negatif dari t = 3 hingga 6 s karena ω\r\nmenurun</span></p>', '<p><span lang=\"IN\" style=\"font-size:11.0pt;line-height:\r\n107%;font-family:&quot;Times New Roman&quot;,serif;mso-ascii-theme-font:major-bidi;\r\nmso-fareast-font-family:Calibri;mso-fareast-theme-font:minor-latin;mso-hansi-theme-font:\r\nmajor-bidi;mso-bidi-theme-font:major-bidi;mso-ansi-language:IN;mso-fareast-language:\r\nEN-US;mso-bidi-language:AR-SA\">torsi bernilai negatif dari t = 0 hingga t = 3 s\r\nkarena ω meningkat, dan torsi bernilai positif dari t = 3 hingga 6 s karena ω\r\nmenurun</span></p>', '<p><span lang=\"IN\" style=\"font-size:11.0pt;line-height:\r\n107%;font-family:&quot;Times New Roman&quot;,serif;mso-ascii-theme-font:major-bidi;\r\nmso-fareast-font-family:Calibri;mso-fareast-theme-font:minor-latin;mso-hansi-theme-font:\r\nmajor-bidi;mso-bidi-theme-font:major-bidi;mso-ansi-language:IN;mso-fareast-language:\r\nEN-US;mso-bidi-language:AR-SA\">torsi tetap bernilai positif karena nilai ω\r\nberkisar pada angka positif&nbsp;</span></p>', '<p><span lang=\"NO-BOK\" style=\"font-size:11.0pt;line-height:\r\n107%;font-family:&quot;Times New Roman&quot;,serif;mso-ascii-theme-font:major-bidi;\r\nmso-fareast-font-family:Calibri;mso-fareast-theme-font:minor-latin;mso-hansi-theme-font:\r\nmajor-bidi;mso-bidi-theme-font:major-bidi;mso-ansi-language:NO-BOK;mso-fareast-language:\r\nEN-US;mso-bidi-language:AR-SA\">torsi tetap bernilai positif karena tidak\r\ndipengaruhi oleh&nbsp;</span><span style=\"font-family: &quot;Times New Roman&quot;, serif; font-size: 11pt;\">ω</span></p>', '<p><span lang=\"SV\" style=\"font-size:11.0pt;line-height:\r\n107%;font-family:&quot;Times New Roman&quot;,serif;mso-ascii-theme-font:major-bidi;\r\nmso-fareast-font-family:Calibri;mso-fareast-theme-font:minor-latin;mso-hansi-theme-font:\r\nmajor-bidi;mso-bidi-theme-font:major-bidi;mso-ansi-language:SV;mso-fareast-language:\r\nEN-US;mso-bidi-language:AR-SA\">torsi bernilai negatif karena berlawanan arah\r\ndengan&nbsp;</span><span style=\"font-family: &quot;Times New Roman&quot;, serif; font-size: 11pt;\">ω</span></p>', '<p><span style=\"font-family: &quot;Times New Roman&quot;, serif; font-size: 14.6667px;\">torsi bernilai positif dari t = 0 hingga t = 3 s karena ω meningkat, dan torsi bernilai negatif dari t = 3 hingga 6 s karena ω menurun</span></p>', NULL, 'A', 2.180, 0, 1, '2026-05-03 16:46:18', '2026-05-03 16:46:18'),
(371, 'ACTofROD23', 11, NULL, '<p><span lang=\"IN\" style=\"font-size:12.0pt;line-height:\r\n107%;font-family:&quot;Times New Roman&quot;,serif;mso-ascii-theme-font:major-bidi;\r\nmso-fareast-font-family:Calibri;mso-fareast-theme-font:minor-latin;mso-hansi-theme-font:\r\nmajor-bidi;mso-bidi-theme-font:major-bidi;mso-ansi-language:IN;mso-fareast-language:\r\nEN-US;mso-bidi-language:AR-SA\">Perhatikan roda kemudi pada gambar 22. Dua gaya\r\nsama besar F bekerja pada tepi roda kemudi yang berjari-jari r. Gaya pertama\r\nbekerja ke atas di sisi kiri, dan gaya kedua bekerja ke bawah di sisi kanan\r\nroda.</span></p><p><img src=\"https://cd-cat.ct.ws/uploads/editor-images/editor_1777763157_69f68355972ac.png\" class=\"img-fluid\" style=\"display: block; max-width: 100%; height: 132.545px; margin: 10px 0px; width: 171.104px;\"><span lang=\"IN\" style=\"font-size:12.0pt;line-height:\r\n107%;font-family:&quot;Times New Roman&quot;,serif;mso-ascii-theme-font:major-bidi;\r\nmso-fareast-font-family:Calibri;mso-fareast-theme-font:minor-latin;mso-hansi-theme-font:\r\nmajor-bidi;mso-bidi-theme-font:major-bidi;mso-ansi-language:IN;mso-fareast-language:\r\nEN-US;mso-bidi-language:AR-SA\"><span lang=\"IN\" style=\"font-size: 12pt; line-height: 107%;\">Pernyataan yang paling tepat berdasarkan\r\nberdasarkan kondisi tersebut adalah....</span></span></p>', '<p><span lang=\"SV\" style=\"font-size:12.0pt;line-height:\r\n107%;font-family:&quot;Times New Roman&quot;,serif;mso-ascii-theme-font:major-bidi;\r\nmso-fareast-font-family:Calibri;mso-fareast-theme-font:minor-latin;mso-hansi-theme-font:\r\nmajor-bidi;mso-bidi-theme-font:major-bidi;mso-ansi-language:SV;mso-fareast-language:\r\nEN-US;mso-bidi-language:AR-SA\">Roda kemudi berada dalam kesetimbangan penuh\r\nkarena resultan gaya dan resultan torsi keduanya bernilai nol&nbsp;</span></p>', '<p><span lang=\"SV\" style=\"font-size:12.0pt;line-height:\r\n107%;font-family:&quot;Times New Roman&quot;,serif;mso-ascii-theme-font:major-bidi;\r\nmso-fareast-font-family:Calibri;mso-fareast-theme-font:minor-latin;mso-hansi-theme-font:\r\nmajor-bidi;mso-bidi-theme-font:major-bidi;mso-ansi-language:SV;mso-fareast-language:\r\nEN-US;mso-bidi-language:AR-SA\">Roda kemudi tidak bergerak sama sekali karena\r\nkedua gaya berlawanan arah sehingga saling meniadakan&nbsp;</span></p>', '<p><span lang=\"SV\" style=\"font-size:12.0pt;line-height:\r\n107%;font-family:&quot;Times New Roman&quot;,serif;mso-ascii-theme-font:major-bidi;\r\nmso-fareast-font-family:Calibri;mso-fareast-theme-font:minor-latin;mso-hansi-theme-font:\r\nmajor-bidi;mso-bidi-theme-font:major-bidi;mso-ansi-language:SV;mso-fareast-language:\r\nEN-US;mso-bidi-language:AR-SA\">Roda kemudi mengalami resultan gaya nol namun\r\nresultan torsi tidak nol sebesar 2FR, sehingga roda berotasi tanpa berpindah posisi&nbsp;</span></p>', '<p><span lang=\"SV\" style=\"font-size:12.0pt;line-height:\r\n107%;font-family:&quot;Times New Roman&quot;,serif;mso-ascii-theme-font:major-bidi;\r\nmso-fareast-font-family:Calibri;mso-fareast-theme-font:minor-latin;mso-hansi-theme-font:\r\nmajor-bidi;mso-bidi-theme-font:major-bidi;mso-ansi-language:SV;mso-fareast-language:\r\nEN-US;mso-bidi-language:AR-SA\">Roda kemudi mengalami translasi karena resultan\r\ngaya dari kedua gaya tersebut tidak nol&nbsp;</span></p>', '<p><span lang=\"SV\" style=\"font-size:12.0pt;line-height:\r\n107%;font-family:&quot;Times New Roman&quot;,serif;mso-ascii-theme-font:major-bidi;\r\nmso-fareast-font-family:Calibri;mso-fareast-theme-font:minor-latin;mso-hansi-theme-font:\r\nmajor-bidi;mso-bidi-theme-font:major-bidi;mso-ansi-language:SV;mso-fareast-language:\r\nEN-US;mso-bidi-language:AR-SA\">Roda kemudi hanya berotasi jika salah satu gaya\r\nlebih besar dari gaya yang lain&nbsp;</span></p>', '<p><span style=\"font-family: &quot;Times New Roman&quot;, serif;\">Roda kemudi mengalami resultan gaya nol namun resultan torsi tidak nol sebesar 2FR, sehingga roda berotasi tanpa berpindah posisi&nbsp;</span></p>', NULL, 'C', -0.341, 0, 1, '2026-05-03 16:46:18', '2026-05-03 16:46:18'),
(372, 'ACTofROD22', 11, NULL, '<p><span lang=\"IN\" style=\"font-size:12.0pt;line-height:\r\n107%;font-family:&quot;Times New Roman&quot;,serif;mso-ascii-theme-font:major-bidi;\r\nmso-fareast-font-family:Calibri;mso-fareast-theme-font:minor-latin;mso-hansi-theme-font:\r\nmajor-bidi;mso-bidi-theme-font:major-bidi;mso-ansi-language:IN;mso-fareast-language:\r\nEN-US;mso-bidi-language:AR-SA\">Perhatikan gambar berikut.</span></p><p><img src=\"https://cd-cat.ct.ws/uploads/editor-images/editor_1777762969_69f68299b5eb2.png\" class=\"img-fluid\" style=\"display: block; max-width: 100%; height: 177.367px; margin: 10px 0px; width: 355.104px;\"></p><p class=\"MsoNormal\" style=\"text-align:justify;line-height:150%\"><span lang=\"IN\" style=\"font-size:12.0pt;line-height:150%;font-family:&quot;Times New Roman&quot;,serif;\r\nmso-ascii-theme-font:major-bidi;mso-hansi-theme-font:major-bidi;mso-bidi-theme-font:\r\nmajor-bidi\">Seorang teknisi sedang menguji dua jenis pintu dalam proyek\r\npembangunan mall. Kedua pintu memiliki massa dan ukuran yang sama. Pintu\r\npertama adalah pintu engsel dengan tuas di ujung pintu. Pintu kedua adalah\r\nsliding door dengan tuas di tengah pintu. <o:p></o:p></span></p><p class=\"MsoNormal\" style=\"text-align:justify;line-height:150%\"><span lang=\"IN\" style=\"font-size:12.0pt;line-height:150%;font-family:&quot;Times New Roman&quot;,serif;\r\nmso-ascii-theme-font:major-bidi;mso-hansi-theme-font:major-bidi;mso-bidi-theme-font:\r\nmajor-bidi\">Teknisi menjelaskan kepada kontraktor: “Kedua pintu sama mudahnya\r\nuntuk dibuka karena massa dan ukurannya identik. Posisi tuas tidak memengaruhi\r\nkemudahan membuka pintu pada kedua jenis pintu tersebut”<o:p></o:p></span></p><p><span lang=\"IN\" style=\"font-size:12.0pt;line-height:\r\n107%;font-family:&quot;Times New Roman&quot;,serif;mso-ascii-theme-font:major-bidi;\r\nmso-fareast-font-family:Calibri;mso-fareast-theme-font:minor-latin;mso-hansi-theme-font:\r\nmajor-bidi;mso-bidi-theme-font:major-bidi;mso-ansi-language:IN;mso-fareast-language:\r\nEN-US;mso-bidi-language:AR-SA\">\r\n\r\n\r\n\r\n<span lang=\"IN\" style=\"font-size: 12pt; line-height: 107%;\">Penilaian\r\nyang paling tepat terhadap pernyataan tersebut adalah....</span></span></p>', '<p><span lang=\"IN\" style=\"font-size:12.0pt;line-height:\r\n107%;font-family:&quot;Times New Roman&quot;,serif;mso-ascii-theme-font:major-bidi;\r\nmso-fareast-font-family:Calibri;mso-fareast-theme-font:minor-latin;mso-hansi-theme-font:\r\nmajor-bidi;mso-bidi-theme-font:major-bidi;mso-ansi-language:IN;mso-fareast-language:\r\nEN-US;mso-bidi-language:AR-SA\">kedua pintu memiliki momen inersia yang sama\r\nsehingga sama mudahnya dibuka dengan gaya F yang sama&nbsp;</span></p>', '<p><span lang=\"IN\" style=\"font-size:12.0pt;line-height:\r\n107%;font-family:&quot;Times New Roman&quot;,serif;mso-ascii-theme-font:major-bidi;\r\nmso-fareast-font-family:Calibri;mso-fareast-theme-font:minor-latin;mso-hansi-theme-font:\r\nmajor-bidi;mso-bidi-theme-font:major-bidi;mso-ansi-language:IN;mso-fareast-language:\r\nEN-US;mso-bidi-language:AR-SA\">posisi tuas tidak relevan karena yang menentukan\r\nkemudahan membuka pintu hanyalah besar gaya F yang diberikan</span></p>', '<p><span lang=\"IN\" style=\"font-size:12.0pt;line-height:\r\n107%;font-family:&quot;Times New Roman&quot;,serif;mso-ascii-theme-font:major-bidi;\r\nmso-fareast-font-family:Calibri;mso-fareast-theme-font:minor-latin;mso-hansi-theme-font:\r\nmajor-bidi;mso-bidi-theme-font:major-bidi;mso-ansi-language:IN;mso-fareast-language:\r\nEN-US;mso-bidi-language:AR-SA\">sliding door lebih mudah dibuka karena tidak\r\nmemiliki momen inersia, sedangkan pintu engsel memiliki momen inersia yang besar&nbsp;</span></p>', '<p><span lang=\"IN\" style=\"font-size:12.0pt;line-height:\r\n107%;font-family:&quot;Times New Roman&quot;,serif;mso-ascii-theme-font:major-bidi;\r\nmso-fareast-font-family:Calibri;mso-fareast-theme-font:minor-latin;mso-hansi-theme-font:\r\nmajor-bidi;mso-bidi-theme-font:major-bidi;mso-ansi-language:IN;mso-fareast-language:\r\nEN-US;mso-bidi-language:AR-SA\">keduanya melibatkan rotasi sehingga posisi tuas\r\npada kedua pintu sama-sama memengaruhi torsi yang dihasilkan&nbsp;</span></p>', '<p><span lang=\"IN\" style=\"font-size:12.0pt;line-height:\r\n107%;font-family:&quot;Times New Roman&quot;,serif;mso-ascii-theme-font:major-bidi;\r\nmso-fareast-font-family:Calibri;mso-fareast-theme-font:minor-latin;mso-hansi-theme-font:\r\nmajor-bidi;mso-bidi-theme-font:major-bidi;mso-ansi-language:IN;mso-fareast-language:\r\nEN-US;mso-bidi-language:AR-SA\">pintu engsel bergerak rotasi sehingga kemudahan\r\nmembukanya ditentukan oleh torsi, sedangkan sliding door bergerak translasi\r\nsehingga kemudahannya ditentukan oleh gaya yang diberikan</span></p>', '<p><span lang=\"IN\" style=\"font-size:12.0pt;line-height:\r\n107%;font-family:&quot;Times New Roman&quot;,serif;mso-ascii-theme-font:major-bidi;\r\nmso-fareast-font-family:Calibri;mso-fareast-theme-font:minor-latin;mso-hansi-theme-font:\r\nmajor-bidi;mso-bidi-theme-font:major-bidi;mso-ansi-language:IN;mso-fareast-language:\r\nEN-US;mso-bidi-language:AR-SA\">pintu engsel bergerak rotasi sehingga kemudahan\r\nmembukanya ditentukan oleh torsi, sedangkan sliding door bergerak translasi\r\nsehingga kemudahannya ditentukan oleh gaya yang diberikan</span></p>', NULL, 'E', -0.620, 0, 1, '2026-05-03 16:46:18', '2026-05-03 16:46:18'),
(373, 'ACTofROD21', 11, NULL, '<p><span lang=\"IN\" style=\"font-size:12.0pt;line-height:\r\n107%;font-family:&quot;Times New Roman&quot;,serif;mso-ascii-theme-font:major-bidi;\r\nmso-fareast-font-family:Calibri;mso-fareast-theme-font:minor-latin;mso-hansi-theme-font:\r\nmajor-bidi;mso-bidi-theme-font:major-bidi;mso-ansi-language:IN;mso-fareast-language:\r\nEN-US;mso-bidi-language:AR-SA\">Sebuah roda bermassa M dan berjari-jari R\r\nberputar dengan kecepatan sudut konstan </span><!--[if gte msEquation 12]><m:oMath><i\r\n style=\'mso-bidi-font-style:normal\'><span lang=IN style=\'font-size:12.0pt;\r\n line-height:107%;font-family:\"Cambria Math\",serif;mso-fareast-font-family:\r\n Calibri;mso-fareast-theme-font:minor-latin;mso-bidi-font-family:\"Times New Roman\";\r\n mso-bidi-theme-font:major-bidi;mso-ansi-language:IN;mso-fareast-language:EN-US;\r\n mso-bidi-language:AR-SA\'><m:r>ω</m:r></span></i></m:oMath><![endif]--><!--[if !msEquation]--><span lang=\"IN\" style=\"font-size:11.0pt;line-height:107%;font-family:&quot;Calibri&quot;,sans-serif;\r\nmso-ascii-theme-font:minor-latin;mso-fareast-font-family:Calibri;mso-fareast-theme-font:\r\nminor-latin;mso-hansi-theme-font:minor-latin;mso-bidi-font-family:Arial;\r\nmso-bidi-theme-font:minor-bidi;position:relative;top:3.5pt;mso-text-raise:-3.5pt;\r\nmso-ansi-language:IN;mso-fareast-language:EN-US;mso-bidi-language:AR-SA\"><v:shapetype id=\"_x0000_t75\" coordsize=\"21600,21600\" o:spt=\"75\" o:preferrelative=\"t\" path=\"m@4@5l@4@11@9@11@9@5xe\" filled=\"f\" stroked=\"f\">\r\n <v:stroke joinstyle=\"miter\">\r\n <v:formulas>\r\n  <v:f eqn=\"if lineDrawn pixelLineWidth 0\">\r\n  <v:f eqn=\"sum @0 1 0\">\r\n  <v:f eqn=\"sum 0 0 @1\">\r\n  <v:f eqn=\"prod @2 1 2\">\r\n  <v:f eqn=\"prod @3 21600 pixelWidth\">\r\n  <v:f eqn=\"prod @3 21600 pixelHeight\">\r\n  <v:f eqn=\"sum @0 0 1\">\r\n  <v:f eqn=\"prod @6 1 2\">\r\n  <v:f eqn=\"prod @7 21600 pixelWidth\">\r\n  <v:f eqn=\"sum @8 21600 0\">\r\n  <v:f eqn=\"prod @7 21600 pixelHeight\">\r\n  <v:f eqn=\"sum @10 21600 0\">\r\n </v:f></v:f></v:f></v:f></v:f></v:f></v:f></v:f></v:f></v:f></v:f></v:f></v:formulas>\r\n <v:path o:extrusionok=\"f\" gradientshapeok=\"t\" o:connecttype=\"rect\">\r\n <o:lock v:ext=\"edit\" aspectratio=\"t\">\r\n</o:lock></v:path></v:stroke></v:shapetype><v:shape id=\"_x0000_i1025\" type=\"#_x0000_t75\" style=\"width:9pt;\r\n height:15pt\">\r\n <v:imagedata src=\"file:///C:/Users/Lenovo/AppData/Local/Temp/msohtmlclip1/01/clip_image001.png\" o:title=\"\" chromakey=\"white\">\r\n</v:imagedata></v:shape></span><!--[endif]--><span lang=\"IN\" style=\"font-size:12.0pt;line-height:\r\n107%;font-family:&quot;Times New Roman&quot;,serif;mso-ascii-theme-font:major-bidi;\r\nmso-fareast-font-family:Calibri;mso-fareast-theme-font:minor-latin;mso-hansi-theme-font:\r\nmajor-bidi;mso-bidi-theme-font:major-bidi;mso-ansi-language:IN;mso-fareast-language:\r\nEN-US;mso-bidi-language:AR-SA\">&nbsp;di\r\nsekitar sumbu yang melalui pusatnya. Energi kinetik rotasi roda adalah Ek dan </span><span lang=\"SV\" style=\"font-size:12.0pt;line-height:107%;font-family:&quot;Times New Roman&quot;,serif;\r\nmso-ascii-theme-font:major-bidi;mso-fareast-font-family:Calibri;mso-fareast-theme-font:\r\nminor-latin;mso-hansi-theme-font:major-bidi;mso-bidi-theme-font:major-bidi;\r\nmso-ansi-language:SV;mso-fareast-language:EN-US;mso-bidi-language:AR-SA\">Momen\r\ninersia roda adalah 0,5MR<sup>2</sup></span><!--[if gte msEquation 12]><m:oMath><i\r\n style=\'mso-bidi-font-style:normal\'><span lang=SV style=\'font-size:12.0pt;\r\n line-height:107%;font-family:\"Cambria Math\",serif;mso-fareast-font-family:\r\n Calibri;mso-fareast-theme-font:minor-latin;mso-bidi-font-family:\"Times New Roman\";\r\n mso-bidi-theme-font:major-bidi;mso-ansi-language:SV;mso-fareast-language:EN-US;\r\n mso-bidi-language:AR-SA\'><m:r>0,5</m:r><m:r>MR</m:r><m:r>²</m:r></span></i></m:oMath><![endif]--><!--[if !msEquation]--><span lang=\"SV\" style=\"font-size:11.0pt;line-height:107%;font-family:&quot;Calibri&quot;,sans-serif;\r\nmso-ascii-theme-font:minor-latin;mso-fareast-font-family:Calibri;mso-fareast-theme-font:\r\nminor-latin;mso-hansi-theme-font:minor-latin;mso-bidi-font-family:Arial;\r\nmso-bidi-theme-font:minor-bidi;position:relative;top:3.5pt;mso-text-raise:-3.5pt;\r\nmso-ansi-language:SV;mso-fareast-language:EN-US;mso-bidi-language:AR-SA\"><v:shape id=\"_x0000_i1025\" type=\"#_x0000_t75\" style=\"width:38.5pt;height:15.5pt\"><v:imagedata src=\"file:///C:/Users/Lenovo/AppData/Local/Temp/msohtmlclip1/01/clip_image002.png\" o:title=\"\" chromakey=\"white\"></v:imagedata></v:shape></span><!--[endif]--><span lang=\"SV\" style=\"font-size:12.0pt;line-height:\r\n107%;font-family:&quot;Times New Roman&quot;,serif;mso-ascii-theme-font:major-bidi;\r\nmso-fareast-font-family:Calibri;mso-fareast-theme-font:minor-latin;mso-hansi-theme-font:\r\nmajor-bidi;mso-bidi-theme-font:major-bidi;mso-ansi-language:SV;mso-fareast-language:\r\nEN-US;mso-bidi-language:AR-SA\">. </span><span lang=\"IN\" style=\"font-size:12.0pt;\r\nline-height:107%;font-family:&quot;Times New Roman&quot;,serif;mso-ascii-theme-font:major-bidi;\r\nmso-fareast-font-family:Calibri;mso-fareast-theme-font:minor-latin;mso-hansi-theme-font:\r\nmajor-bidi;mso-bidi-theme-font:major-bidi;mso-ansi-language:IN;mso-fareast-language:\r\nEN-US;mso-bidi-language:AR-SA\">Sebuah roda kedua bermassa 0,5M dan berjari-jari\r\n0,5R diletakkan di atas roda pertama. Kecepatan sudut baru dari gabungan kedua roda\r\nadalah 2/3</span><span style=\"color: rgb(31, 31, 31); font-family: &quot;Google Sans&quot;, Arial, sans-serif; font-size: 14px;\">ω.</span></p><p><img src=\"https://cd-cat.ct.ws/uploads/editor-images/editor_1777762763_69f681cb4880f.png\" class=\"img-fluid\" style=\"display: block; max-width: 100%; height: 197.244px; margin: 10px 0px; width: 245.104px;\"></p><p class=\"MsoNormal\" align=\"center\" style=\"text-align:center;line-height:150%\"><span lang=\"IN\" style=\"font-size:12.0pt;line-height:150%;font-family:&quot;Times New Roman&quot;,serif;\r\nmso-ascii-theme-font:major-bidi;mso-hansi-theme-font:major-bidi;mso-bidi-theme-font:\r\nmajor-bidi\">Gambar 21. Dua roda yang dihubungkan pada sumbu rotasi yang sama</span></p><p class=\"Default\" style=\"text-align:justify;line-height:150%\"><span lang=\"IN\" style=\"font-family:&quot;Times New Roman&quot;,serif;mso-ascii-theme-font:major-bidi;\r\nmso-hansi-theme-font:major-bidi;mso-bidi-theme-font:major-bidi;mso-ansi-language:\r\nIN\">Naro memberikan pendapat bahwa “Karena kecepatan sudut berkurang dari&nbsp;</span><span style=\"color: rgb(31, 31, 31); font-family: &quot;Google Sans&quot;, Arial, sans-serif; font-size: 14px; text-align: start;\">ω&nbsp;</span><span lang=\"IN\" style=\"font-size: 1rem; font-family: &quot;Times New Roman&quot;, serif;\">menjadi 2/3</span><span style=\"color: rgb(31, 31, 31); font-family: &quot;Google Sans&quot;, Arial, sans-serif; font-size: 14px; text-align: start;\">ω</span><span lang=\"IN\" style=\"font-size: 1rem; font-family: &quot;Times New Roman&quot;, serif;\">, maka energi kinetik rotasi sistem juga hanya\r\nbergantung pada kecepatan sudut. Jadi energi kinetik akhirnya menjadi 1/3 E<sub>k</sub></span><span lang=\"IN\" style=\"font-size: 11pt; line-height: 107%; font-family: Calibri, sans-serif; position: relative; top: 6pt;\"><v:shape id=\"_x0000_i1025\" type=\"#_x0000_t75\" style=\"width:19.5pt;height:20pt\"><v:imagedata src=\"file:///C:/Users/Lenovo/AppData/Local/Temp/msohtmlclip1/01/clip_image003.png\" o:title=\"\" chromakey=\"white\"></v:imagedata></v:shape></span><span lang=\"IN\" style=\"font-size: 1rem; font-family: &quot;Times New Roman&quot;, serif;\">”</span></p><p>\r\n\r\n\r\n\r\n\r\n\r\n<span lang=\"IN\" style=\"font-size:11.0pt;line-height:107%;font-family:&quot;Times New Roman&quot;,serif;\r\nmso-ascii-theme-font:major-bidi;mso-fareast-font-family:Calibri;mso-fareast-theme-font:\r\nminor-latin;mso-hansi-theme-font:major-bidi;mso-bidi-theme-font:major-bidi;\r\nmso-ansi-language:IN;mso-fareast-language:EN-US;mso-bidi-language:AR-SA\">Penilaian\r\nyang paling tepat terhadap pendapat Naro adalah....</span><span style=\"color: rgb(31, 31, 31); font-family: &quot;Google Sans&quot;, Arial, sans-serif; font-size: 14px;\"></span><!--[endif]--></p><!--[if gte msEquation 12]><m:oMathPara><m:oMath><i\r\n  style=\'mso-bidi-font-style:normal\'><span lang=IN style=\'font-size:12.0pt;\r\n  line-height:107%;font-family:\"Cambria Math\",serif;mso-fareast-font-family:\r\n  Calibri;mso-fareast-theme-font:minor-latin;mso-bidi-font-family:\"Times New Roman\";\r\n  mso-bidi-theme-font:major-bidi;mso-ansi-language:IN;mso-fareast-language:\r\n  EN-US;mso-bidi-language:AR-SA\'><m:r>ω</m:r></span></i></m:oMath></m:oMathPara><![endif]--><!--[if !msEquation]--><span lang=\"IN\" style=\"font-size:11.0pt;line-height:107%;font-family:&quot;Calibri&quot;,sans-serif;\r\nmso-ascii-theme-font:minor-latin;mso-fareast-font-family:Calibri;mso-fareast-theme-font:\r\nminor-latin;mso-hansi-theme-font:minor-latin;mso-bidi-font-family:Arial;\r\nmso-bidi-theme-font:minor-bidi;mso-ansi-language:IN;mso-fareast-language:EN-US;\r\nmso-bidi-language:AR-SA\"><v:shapetype id=\"_x0000_t75\" coordsize=\"21600,21600\" o:spt=\"75\" o:preferrelative=\"t\" path=\"m@4@5l@4@11@9@11@9@5xe\" filled=\"f\" stroked=\"f\">\r\n <v:stroke joinstyle=\"miter\">\r\n <v:formulas>\r\n  <v:f eqn=\"if lineDrawn pixelLineWidth 0\">\r\n  <v:f eqn=\"sum @0 1 0\">\r\n  <v:f eqn=\"sum 0 0 @1\">\r\n  <v:f eqn=\"prod @2 1 2\">\r\n  <v:f eqn=\"prod @3 21600 pixelWidth\">\r\n  <v:f eqn=\"prod @3 21600 pixelHeight\">\r\n  <v:f eqn=\"sum @0 0 1\">\r\n  <v:f eqn=\"prod @6 1 2\">\r\n  <v:f eqn=\"prod @7 21600 pixelWidth\">\r\n  <v:f eqn=\"sum @8 21600 0\">\r\n  <v:f eqn=\"prod @7 21600 pixelHeight\">\r\n  <v:f eqn=\"sum @10 21600 0\">\r\n </v:f></v:f></v:f></v:f></v:f></v:f></v:f></v:f></v:f></v:f></v:f></v:f></v:formulas>\r\n <v:path o:extrusionok=\"f\" gradientshapeok=\"t\" o:connecttype=\"rect\">\r\n <o:lock v:ext=\"edit\" aspectratio=\"t\">\r\n</o:lock></v:path></v:stroke></v:shapetype><v:shape id=\"_x0000_i1025\" type=\"#_x0000_t75\" style=\"width:9pt;\r\n height:15pt\">\r\n <v:imagedata src=\"file:///C:/Users/Lenovo/AppData/Local/Temp/msohtmlclip1/01/clip_image001.png\" o:title=\"\" chromakey=\"white\">\r\n</v:imagedata></v:shape></span><!--[endif]-->', '<p><span lang=\"IN\" style=\"font-size:11.0pt;line-height:\r\n107%;font-family:&quot;Times New Roman&quot;,serif;mso-ascii-theme-font:major-bidi;\r\nmso-fareast-font-family:Calibri;mso-fareast-theme-font:minor-latin;mso-hansi-theme-font:\r\nmajor-bidi;mso-bidi-theme-font:major-bidi;mso-ansi-language:IN;mso-fareast-language:\r\nEN-US;mso-bidi-language:AR-SA\">pernyataan Naro tepat sebagian, karena perubahan\r\nenergi kinetik rotasi juga disebabkan oleh momen inersia yang meningkat\r\nsehingga energi kinetik akhirnya 1/2 Ek&nbsp;</span></p>', '<p><span lang=\"IN\" style=\"font-size:11.0pt;line-height:\r\n107%;font-family:&quot;Times New Roman&quot;,serif;mso-ascii-theme-font:major-bidi;\r\nmso-fareast-font-family:Calibri;mso-fareast-theme-font:minor-latin;mso-hansi-theme-font:\r\nmajor-bidi;mso-bidi-theme-font:major-bidi;mso-ansi-language:IN;mso-fareast-language:\r\nEN-US;mso-bidi-language:AR-SA\">pernyataan Naro tidak tepat, karena kecepatan\r\nsudut berkurang disebabkan oleh momen inersia yang meningkat sehingga energi\r\nkinetik akhirnya 1/4 Ek&nbsp;</span></p>', '<p><span lang=\"IN\" style=\"font-size:11.0pt;line-height:\r\n107%;font-family:&quot;Times New Roman&quot;,serif;mso-ascii-theme-font:major-bidi;\r\nmso-fareast-font-family:Calibri;mso-fareast-theme-font:minor-latin;mso-hansi-theme-font:\r\nmajor-bidi;mso-bidi-theme-font:major-bidi;mso-ansi-language:IN;mso-fareast-language:\r\nEN-US;mso-bidi-language:AR-SA\">pernyataan Naro tidak tepat, karena kecepatan\r\nsudut berkurang disebabkan oleh momen inersia yang meningkat sehingga energi\r\nkinetik akhirnya 1/2 Ek&nbsp;</span></p>', '<p><span lang=\"IN\" style=\"font-size:11.0pt;line-height:\r\n107%;font-family:&quot;Times New Roman&quot;,serif;mso-ascii-theme-font:major-bidi;\r\nmso-fareast-font-family:Calibri;mso-fareast-theme-font:minor-latin;mso-hansi-theme-font:\r\nmajor-bidi;mso-bidi-theme-font:major-bidi;mso-ansi-language:IN;mso-fareast-language:\r\nEN-US;mso-bidi-language:AR-SA\">pernyataan Naro tepat, karena perubahan energi\r\nkinetik rotasi disebabkan oleh kecepatan sudut berkurang sehingga energi\r\nkinetik akhirnya 1/2 Ek&nbsp;</span></p>', '<p><span lang=\"IN\" style=\"font-size:11.0pt;line-height:\r\n107%;font-family:&quot;Times New Roman&quot;,serif;mso-ascii-theme-font:major-bidi;\r\nmso-fareast-font-family:Calibri;mso-fareast-theme-font:minor-latin;mso-hansi-theme-font:\r\nmajor-bidi;mso-bidi-theme-font:major-bidi;mso-ansi-language:IN;mso-fareast-language:\r\nEN-US;mso-bidi-language:AR-SA\">pernyataan Naro tepat sebagian, karena perubahan\r\nenergi kinetik rotasi juga disebabkan oleh momen inersia yang meningkat\r\nsehingga energi kinetik akhirnya 1/4 Ek&nbsp;</span></p>', '<p><span style=\"font-family: &quot;Times New Roman&quot;, serif; font-size: 14.6667px;\">pernyataan Naro tepat sebagian, karena perubahan energi kinetik rotasi juga disebabkan oleh momen inersia yang meningkat sehingga energi kinetik akhirnya 1/2 Ek&nbsp;</span></p>', NULL, 'A', -2.591, 0, 1, '2026-05-03 16:46:18', '2026-05-03 16:46:18'),
(374, 'ACTofROD20', 11, NULL, '<p><span lang=\"IN\" style=\"font-size:11.0pt;line-height:\r\n107%;font-family:&quot;Times New Roman&quot;,serif;mso-ascii-theme-font:major-bidi;\r\nmso-fareast-font-family:Calibri;mso-fareast-theme-font:minor-latin;mso-hansi-theme-font:\r\nmajor-bidi;mso-bidi-theme-font:major-bidi;mso-ansi-language:IN;mso-fareast-language:\r\nEN-US;mso-bidi-language:AR-SA\">Suatu sistem yang terdiri dari dua roda saling\r\nterhubung dan berputar pada sumbu rotasi sama yang melalui pusat kedua roda. </span><span lang=\"SV\" style=\"font-size:11.0pt;line-height:107%;font-family:&quot;Times New Roman&quot;,serif;\r\nmso-ascii-theme-font:major-bidi;mso-fareast-font-family:Calibri;mso-fareast-theme-font:\r\nminor-latin;mso-hansi-theme-font:major-bidi;mso-bidi-theme-font:major-bidi;\r\nmso-ansi-language:SV;mso-fareast-language:EN-US;mso-bidi-language:AR-SA\">Roda\r\npertama dengan jari-jari 3R dan roda kedua dengan jari-jari 2R.&nbsp; Empat gaya diberikan pada tepi roda, seperti\r\nyang ditunjukkan pada gambar 20.</span></p><p><img src=\"https://cd-cat.ct.ws/uploads/editor-images/editor_1777762515_69f680d31b21e.png\" class=\"img-fluid\" style=\"display: block; max-width: 100%; height: 179.948px; margin: 10px 0px; width: 314.906px;\"></p><p align=\"center\" style=\"margin-bottom:0cm;text-align:center;line-height:150%\"><span lang=\"SV\">Gambar 20. Dua roda berputar pada sumbu rotasi sama\r\ndiberi gaya dari beberapa arah<o:p></o:p></span></p><p class=\"MsoNormal\" style=\"text-align:justify;line-height:150%;mso-layout-grid-align:\r\nnone;text-autospace:none\"><span lang=\"SV\" style=\"font-size:12.0pt;line-height:\r\n150%;font-family:&quot;Times New Roman&quot;,serif;mso-ascii-theme-font:major-bidi;\r\nmso-hansi-theme-font:major-bidi;mso-bidi-theme-font:major-bidi;mso-font-kerning:\r\n0pt;mso-ansi-language:SV\">Seorang siswa, Andi, menyatakan: “Karena gaya\r\nterbesar adalah </span><!--[if gte msEquation 12]><m:oMath><i style=\'mso-bidi-font-style:\r\n normal\'><span lang=SV style=\'font-size:12.0pt;line-height:150%;font-family:\r\n \"Cambria Math\",serif;mso-bidi-font-family:\"Times New Roman\";mso-bidi-theme-font:\r\n major-bidi;mso-font-kerning:0pt;mso-ansi-language:SV\'><m:r>2</m:r></span></i><i\r\n style=\'mso-bidi-font-style:normal\'><span style=\'font-size:12.0pt;line-height:\r\n 150%;font-family:\"Cambria Math\",serif;mso-bidi-font-family:\"Times New Roman\";\r\n mso-bidi-theme-font:major-bidi;mso-font-kerning:0pt;mso-ansi-language:EN-ID\'><m:r>F</m:r></span></i></m:oMath><![endif]--><!--[if !msEquation]--><span lang=\"SV\" style=\"font-size:11.0pt;line-height:107%;font-family:&quot;Calibri&quot;,sans-serif;\r\nmso-ascii-theme-font:minor-latin;mso-fareast-font-family:Calibri;mso-fareast-theme-font:\r\nminor-latin;mso-hansi-theme-font:minor-latin;mso-bidi-font-family:Arial;\r\nmso-bidi-theme-font:minor-bidi;position:relative;top:3.5pt;mso-text-raise:-3.5pt;\r\nmso-ansi-language:SV;mso-fareast-language:EN-US;mso-bidi-language:AR-SA\"><v:shapetype id=\"_x0000_t75\" coordsize=\"21600,21600\" o:spt=\"75\" o:preferrelative=\"t\" path=\"m@4@5l@4@11@9@11@9@5xe\" filled=\"f\" stroked=\"f\">\r\n <v:stroke joinstyle=\"miter\">\r\n <v:formulas>\r\n  <v:f eqn=\"if lineDrawn pixelLineWidth 0\">\r\n  <v:f eqn=\"sum @0 1 0\">\r\n  <v:f eqn=\"sum 0 0 @1\">\r\n  <v:f eqn=\"prod @2 1 2\">\r\n  <v:f eqn=\"prod @3 21600 pixelWidth\">\r\n  <v:f eqn=\"prod @3 21600 pixelHeight\">\r\n  <v:f eqn=\"sum @0 0 1\">\r\n  <v:f eqn=\"prod @6 1 2\">\r\n  <v:f eqn=\"prod @7 21600 pixelWidth\">\r\n  <v:f eqn=\"sum @8 21600 0\">\r\n  <v:f eqn=\"prod @7 21600 pixelHeight\">\r\n  <v:f eqn=\"sum @10 21600 0\">\r\n </v:f></v:f></v:f></v:f></v:f></v:f></v:f></v:f></v:f></v:f></v:f></v:f></v:formulas>\r\n <v:path o:extrusionok=\"f\" gradientshapeok=\"t\" o:connecttype=\"rect\">\r\n <o:lock v:ext=\"edit\" aspectratio=\"t\">\r\n</o:lock></v:path></v:stroke></v:shapetype><v:shape id=\"_x0000_i1025\" type=\"#_x0000_t75\" style=\"width:14.5pt;\r\n height:15pt\">\r\n <v:imagedata src=\"file:///C:/Users/Lenovo/AppData/Local/Temp/msohtmlclip1/01/clip_image001.png\" o:title=\"\" chromakey=\"white\">\r\n</v:imagedata></v:shape></span><!--[endif]--><span style=\"font-size:12.0pt;line-height:150%;\r\nfont-family:&quot;Times New Roman&quot;,serif;mso-ascii-theme-font:major-bidi;mso-fareast-font-family:\r\n&quot;Times New Roman&quot;;mso-fareast-theme-font:minor-fareast;mso-hansi-theme-font:\r\nmajor-bidi;mso-bidi-theme-font:major-bidi;mso-font-kerning:0pt;mso-ansi-language:\r\nSV\">&nbsp;</span><span lang=\"SV\" style=\"font-size:12.0pt;line-height:150%;font-family:&quot;Times New Roman&quot;,serif;\r\nmso-ascii-theme-font:major-bidi;mso-hansi-theme-font:major-bidi;mso-bidi-theme-font:\r\nmajor-bidi;mso-font-kerning:0pt;mso-ansi-language:SV\">yang bekerja pada\r\njari-jari terbesar yaitu </span><!--[if gte msEquation 12]><m:oMath><i\r\n style=\'mso-bidi-font-style:normal\'><span lang=SV style=\'font-size:12.0pt;\r\n line-height:150%;font-family:\"Cambria Math\",serif;mso-bidi-font-family:\"Times New Roman\";\r\n mso-bidi-theme-font:major-bidi;mso-font-kerning:0pt;mso-ansi-language:SV\'><m:r>3</m:r></span></i><i\r\n style=\'mso-bidi-font-style:normal\'><span style=\'font-size:12.0pt;line-height:\r\n 150%;font-family:\"Cambria Math\",serif;mso-bidi-font-family:\"Times New Roman\";\r\n mso-bidi-theme-font:major-bidi;mso-font-kerning:0pt;mso-ansi-language:EN-ID\'><m:r>R</m:r></span></i></m:oMath><![endif]--><!--[if !msEquation]--><span lang=\"SV\" style=\"font-size:11.0pt;line-height:107%;font-family:&quot;Calibri&quot;,sans-serif;\r\nmso-ascii-theme-font:minor-latin;mso-fareast-font-family:Calibri;mso-fareast-theme-font:\r\nminor-latin;mso-hansi-theme-font:minor-latin;mso-bidi-font-family:Arial;\r\nmso-bidi-theme-font:minor-bidi;position:relative;top:3.5pt;mso-text-raise:-3.5pt;\r\nmso-ansi-language:SV;mso-fareast-language:EN-US;mso-bidi-language:AR-SA\"><v:shape id=\"_x0000_i1025\" type=\"#_x0000_t75\" style=\"width:14.5pt;height:15pt\">\r\n <v:imagedata src=\"file:///C:/Users/Lenovo/AppData/Local/Temp/msohtmlclip1/01/clip_image002.png\" o:title=\"\" chromakey=\"white\">\r\n</v:imagedata></v:shape></span><!--[endif]--><span lang=\"SV\" style=\"font-size:12.0pt;line-height:\r\n150%;font-family:&quot;Times New Roman&quot;,serif;mso-ascii-theme-font:major-bidi;\r\nmso-hansi-theme-font:major-bidi;mso-bidi-theme-font:major-bidi;mso-font-kerning:\r\n0pt;mso-ansi-language:SV\">, maka torsi total sistem searah jarum jam dan\r\nbernilai 6FR.”<o:p></o:p></span></p><p><span lang=\"SV\" style=\"font-size:11.0pt;line-height:107%;font-family:&quot;Times New Roman&quot;,serif;\r\nmso-ascii-theme-font:major-bidi;mso-fareast-font-family:Calibri;mso-fareast-theme-font:\r\nminor-latin;mso-hansi-theme-font:major-bidi;mso-bidi-theme-font:major-bidi;\r\nmso-ansi-language:SV;mso-fareast-language:EN-US;mso-bidi-language:AR-SA\">\r\n\r\n\r\n\r\n<span lang=\"SV\" style=\"font-size: 12pt; line-height: 107%;\">Tanggapan yang paling tepat terhadap pernyataan Andi\r\nadalah....</span></span></p>', '<p><span lang=\"IN\" style=\"font-size:12.0pt;line-height:\r\n107%;font-family:&quot;Times New Roman&quot;,serif;mso-ascii-theme-font:major-bidi;\r\nmso-fareast-font-family:Calibri;mso-fareast-theme-font:minor-latin;mso-hansi-theme-font:\r\nmajor-bidi;mso-bidi-theme-font:major-bidi;mso-font-kerning:0pt;mso-ansi-language:\r\nIN;mso-fareast-language:EN-US;mso-bidi-language:AR-SA\">pernyataan Andi tidak\r\ntepat, karena gaya yang menghasilkan torsi berlawanan arah jarum jam lebih\r\nbesar sehingga torsi total adalah 2FR berlawanan arah jarum jam</span></p>', '<p><span lang=\"IN\" style=\"font-size:12.0pt;line-height:\r\n107%;font-family:&quot;Times New Roman&quot;,serif;mso-ascii-theme-font:major-bidi;\r\nmso-fareast-font-family:Calibri;mso-fareast-theme-font:minor-latin;mso-hansi-theme-font:\r\nmajor-bidi;mso-bidi-theme-font:major-bidi;mso-font-kerning:0pt;mso-ansi-language:\r\nIN;mso-fareast-language:EN-US;mso-bidi-language:AR-SA\">pernyataan Andi tidak\r\ntepat, karena gaya yang menghasilkan torsi berlawanan arah jarum jam lebih\r\nbesar sehingga torsi total adalah 4FR berlawanan arah jarum jam&nbsp;</span></p>', '<p><span lang=\"IN\" style=\"font-size:12.0pt;line-height:\r\n107%;font-family:&quot;Times New Roman&quot;,serif;mso-ascii-theme-font:major-bidi;\r\nmso-fareast-font-family:Calibri;mso-fareast-theme-font:minor-latin;mso-hansi-theme-font:\r\nmajor-bidi;mso-bidi-theme-font:major-bidi;mso-font-kerning:0pt;mso-ansi-language:\r\nIN;mso-fareast-language:EN-US;mso-bidi-language:AR-SA\">pernyataan Andi tidak\r\ntepat, karena gaya yang menghasilkan torsi berlawanan arah jarum jam lebih\r\nbesar sehingga torsi total adalah 6FR berlawanan arah jarum jam&nbsp;</span></p>', '<p><span lang=\"IN\" style=\"font-size:12.0pt;line-height:\r\n107%;font-family:&quot;Times New Roman&quot;,serif;mso-ascii-theme-font:major-bidi;\r\nmso-fareast-font-family:Calibri;mso-fareast-theme-font:minor-latin;mso-hansi-theme-font:\r\nmajor-bidi;mso-bidi-theme-font:major-bidi;mso-font-kerning:0pt;mso-ansi-language:\r\nIN;mso-fareast-language:EN-US;mso-bidi-language:AR-SA\">pernyataan Andi tepat,\r\nkarena gaya yang menghasilkan torsi searah jarum jam lebih besar sehingga torsi\r\ntotal adalah 6FR searah jarum jam&nbsp;</span></p>', '<p><span lang=\"IN\" style=\"font-size:12.0pt;line-height:\r\n107%;font-family:&quot;Times New Roman&quot;,serif;mso-ascii-theme-font:major-bidi;\r\nmso-fareast-font-family:Calibri;mso-fareast-theme-font:minor-latin;mso-hansi-theme-font:\r\nmajor-bidi;mso-bidi-theme-font:major-bidi;mso-font-kerning:0pt;mso-ansi-language:\r\nIN;mso-fareast-language:EN-US;mso-bidi-language:AR-SA\">pernyataan Andi tepat,\r\nkarena gaya yang menghasilkan torsi searah jarum jam lebih besar sehingga torsi\r\ntotal adalah 2FR searah jarum jam&nbsp;</span></p>', '<p><span style=\"font-family: &quot;Times New Roman&quot;, serif;\">pernyataan Andi tidak tepat, karena gaya yang menghasilkan torsi berlawanan arah jarum jam lebih besar sehingga torsi total adalah 2FR berlawanan arah jarum jam</span></p>', NULL, 'A', 1.020, 0, 1, '2026-05-03 16:46:18', '2026-05-03 16:46:18');
INSERT INTO `soal_ujian` (`soal_id`, `kode_soal`, `ujian_id`, `bank_ujian_id`, `pertanyaan`, `pilihan_a`, `pilihan_b`, `pilihan_c`, `pilihan_d`, `pilihan_e`, `pembahasan`, `foto`, `jawaban_benar`, `tingkat_kesulitan`, `is_bank_soal`, `created_by`, `created_at`, `updated_at`) VALUES
(375, 'ACTofROD19', 11, NULL, '<p><span lang=\"IN\" style=\"font-size:11.0pt;line-height:\r\n107%;font-family:&quot;Times New Roman&quot;,serif;mso-ascii-theme-font:major-bidi;\r\nmso-fareast-font-family:Calibri;mso-fareast-theme-font:minor-latin;mso-hansi-theme-font:\r\nmajor-bidi;mso-bidi-theme-font:major-bidi;mso-ansi-language:IN;mso-fareast-language:\r\nEN-US;mso-bidi-language:AR-SA\">Rina memperhatikan seorang ayah mendorong komedi\r\nputar bermassa 15 kg berjari-jari 1,5 m dengan gaya 250 N di tepinya. Anggap\r\nkomedi putar sebagai cakram seragam dan gesekan diabaikan.</span></p><p><img src=\"https://cd-cat.ct.ws/uploads/editor-images/editor_1777762210_69f67fa256443.png\" class=\"img-fluid\" style=\"display: block; max-width: 100%; height: 139.108px; margin: 10px 0px; width: 443.104px;\"></p><p align=\"center\" style=\"margin:0cm;text-align:center;line-height:150%\">Gambar 19.\r\nAyah mendorong komedi putar</p><ul><li><span lang=\"IN\" style=\"font-size:11.0pt;line-height:\r\n107%;font-family:&quot;Times New Roman&quot;,serif;mso-ascii-theme-font:major-bidi;\r\nmso-fareast-font-family:Calibri;mso-fareast-theme-font:minor-latin;mso-hansi-theme-font:\r\nmajor-bidi;mso-bidi-theme-font:major-bidi;mso-ansi-language:IN;mso-fareast-language:\r\nEN-US;mso-bidi-language:AR-SA\"><span lang=\"IN\" style=\"font-size: 11pt; line-height: 107%;\">kondisi 1: komedi putar didorong tanpa anak</span></span></li><li><span lang=\"IN\" style=\"font-size:11.0pt;line-height:\r\n107%;font-family:&quot;Times New Roman&quot;,serif;mso-ascii-theme-font:major-bidi;\r\nmso-fareast-font-family:Calibri;mso-fareast-theme-font:minor-latin;mso-hansi-theme-font:\r\nmajor-bidi;mso-bidi-theme-font:major-bidi;mso-ansi-language:IN;mso-fareast-language:\r\nEN-US;mso-bidi-language:AR-SA\"><span lang=\"IN\" style=\"font-size: 11pt; line-height: 107%;\">kondisi2:&nbsp;</span></span><span lang=\"IN\" style=\"font-size:11.0pt;line-height:\r\n107%;font-family:&quot;Times New Roman&quot;,serif;mso-ascii-theme-font:major-bidi;\r\nmso-fareast-font-family:Calibri;mso-fareast-theme-font:minor-latin;mso-hansi-theme-font:\r\nmajor-bidi;mso-bidi-theme-font:major-bidi;mso-ansi-language:IN;mso-fareast-language:\r\nEN-US;mso-bidi-language:AR-SA\">komedi putar didorong dengan anak bermassa 18 kg\r\nduduk berjarak 1,25m dari pusat</span></li></ul><p class=\"Default\" style=\"text-align:justify;line-height:150%\"><span lang=\"IN\" style=\"font-family:&quot;Times New Roman&quot;,serif;mso-ascii-theme-font:major-bidi;\r\nmso-hansi-theme-font:major-bidi;mso-bidi-theme-font:major-bidi;mso-ansi-language:\r\nIN\">Rina berpendapat “Percepatan sudut pada Kondisi 1 dan Kondisi 2 adalah\r\nsama, karena anak tidak memberikan gaya dorong sehingga tidak memengaruhi gerak\r\nrotasi”<o:p></o:p></span></p><p><span lang=\"IN\" style=\"font-size:11.0pt;line-height:\r\n107%;font-family:&quot;Times New Roman&quot;,serif;mso-ascii-theme-font:major-bidi;\r\nmso-fareast-font-family:Calibri;mso-fareast-theme-font:minor-latin;mso-hansi-theme-font:\r\nmajor-bidi;mso-bidi-theme-font:major-bidi;mso-ansi-language:IN;mso-fareast-language:\r\nEN-US;mso-bidi-language:AR-SA\">\r\n\r\n<span lang=\"IN\" style=\"font-size: 11pt; line-height: 107%;\">Penilaian\r\nyang paling tepat terhadap pendapat Rina adalah....</span></span></p>', '<p><span lang=\"IN\" style=\"font-size:11.0pt;line-height:\r\n107%;font-family:&quot;Times New Roman&quot;,serif;mso-ascii-theme-font:major-bidi;\r\nmso-fareast-font-family:Calibri;mso-fareast-theme-font:minor-latin;mso-hansi-theme-font:\r\nmajor-bidi;mso-bidi-theme-font:major-bidi;mso-ansi-language:IN;mso-fareast-language:\r\nEN-US;mso-bidi-language:AR-SA\">Rina benar, karena anak tidak memberikan torsi\r\nsehingga percepatan sudut tetap 6,67 rad/s² pada kedua kondisi&nbsp;</span></p>', '<p><span lang=\"IN\" style=\"font-size:11.0pt;line-height:\r\n107%;font-family:&quot;Times New Roman&quot;,serif;mso-ascii-theme-font:major-bidi;\r\nmso-fareast-font-family:Calibri;mso-fareast-theme-font:minor-latin;mso-hansi-theme-font:\r\nmajor-bidi;mso-bidi-theme-font:major-bidi;mso-ansi-language:IN;mso-fareast-language:\r\nEN-US;mso-bidi-language:AR-SA\">Rina tidak tepat karena pada kondisi 2\r\npercepatan sudut lebih besar menjadi 5,12 rad/s² karena anak menambah gaya\r\ntotal sistem&nbsp;</span></p>', '<p><span lang=\"IN\" style=\"font-size:11.0pt;line-height:\r\n107%;font-family:&quot;Times New Roman&quot;,serif;mso-ascii-theme-font:major-bidi;\r\nmso-fareast-font-family:Calibri;mso-fareast-theme-font:minor-latin;mso-hansi-theme-font:\r\nmajor-bidi;mso-bidi-theme-font:major-bidi;mso-ansi-language:IN;mso-fareast-language:\r\nEN-US;mso-bidi-language:AR-SA\">Rina tidak tepat karena pada kondisi 2\r\npercepatan sudut lebih kecil menjadi 4,44 rad/s² karena massa anak menambah\r\nmomen inersia sistem&nbsp;</span></p>', '<p><span lang=\"IN\" style=\"font-size:11.0pt;line-height:\r\n107%;font-family:&quot;Times New Roman&quot;,serif;mso-ascii-theme-font:major-bidi;\r\nmso-fareast-font-family:Calibri;mso-fareast-theme-font:minor-latin;mso-hansi-theme-font:\r\nmajor-bidi;mso-bidi-theme-font:major-bidi;mso-ansi-language:IN;mso-fareast-language:\r\nEN-US;mso-bidi-language:AR-SA\">Rina tidak tepat karena pada kondisi 2\r\npercepatan sudut lebih kecil menjadi 3,34 rad/s² karena massa anak mengurangi\r\ntorsi yang bekerja&nbsp;</span></p>', '<p><span lang=\"IN\" style=\"font-size:11.0pt;line-height:\r\n107%;font-family:&quot;Times New Roman&quot;,serif;mso-ascii-theme-font:major-bidi;\r\nmso-fareast-font-family:Calibri;mso-fareast-theme-font:minor-latin;mso-hansi-theme-font:\r\nmajor-bidi;mso-bidi-theme-font:major-bidi;mso-ansi-language:IN;mso-fareast-language:\r\nEN-US;mso-bidi-language:AR-SA\">Rina tidak tepat karena pada kondisi 2\r\npercepatan sudut lebih kecil menjadi 2,67 rad/s² karena massa anak memperkecil\r\nmomen inersia sistem&nbsp;</span></p>', '<p><span style=\"font-family: &quot;Times New Roman&quot;, serif; font-size: 14.6667px;\">Rina tidak tepat karena pada kondisi 2 percepatan sudut lebih kecil menjadi 4,44 rad/s² karena massa anak menambah momen inersia sistem&nbsp;</span></p>', NULL, 'C', 1.019, 0, 1, '2026-05-03 16:46:18', '2026-05-03 16:46:18'),
(376, 'ACTofROD18', 11, NULL, '<p><span lang=\"IN\" style=\"font-size:12.0pt;line-height:\r\n107%;font-family:&quot;Times New Roman&quot;,serif;mso-ascii-theme-font:major-bidi;\r\nmso-fareast-font-family:Calibri;mso-fareast-theme-font:minor-latin;mso-hansi-theme-font:\r\nmajor-bidi;mso-bidi-theme-font:major-bidi;mso-ansi-language:IN;mso-fareast-language:\r\nEN-US;mso-bidi-language:AR-SA\">Gambar 18 menunjukkan prinsip kerja pengering\r\nsayuran untuk mengeringkan sayuran yang telah dicuci.</span></p><p><img src=\"https://cd-cat.ct.ws/uploads/editor-images/editor_1777762055_69f67f0795ade.png\" class=\"img-fluid\" style=\"display: block; max-width: 100%; height: 190.322px; margin: 10px 0px; width: 262.104px;\"></p><p class=\"MsoNormal\" align=\"center\" style=\"text-align:center;line-height:150%\"><span lang=\"IN\" style=\"font-size:12.0pt;line-height:150%;font-family:&quot;Times New Roman&quot;,serif;\r\nmso-ascii-theme-font:major-bidi;mso-hansi-theme-font:major-bidi;mso-bidi-theme-font:\r\nmajor-bidi\">Gambar 18. Prinsip kerja pengering sayuran</span></p><p class=\"MsoListParagraph\" style=\"margin-left:0cm;mso-add-space:auto;text-align:\r\njustify;line-height:150%\"><span lang=\"IN\" style=\"font-size:12.0pt;line-height:\r\n150%;font-family:&quot;Times New Roman&quot;,serif;mso-ascii-theme-font:major-bidi;\r\nmso-hansi-theme-font:major-bidi;mso-bidi-theme-font:major-bidi\">Sayuran\r\nditempatkan dalam keranjang dan tutupnya dipasang. Ketika pegangan A diputar,\r\nkeranjang dan isinya berputar dengan cepat. Air pada sayuran terdorong melalui\r\nlubang-lubang di keranjang ke dalam mangkuk penampung air. Poros untuk\r\ngear&nbsp; B dipasang pada tutup. Ketika gear\r\nB berputar, gear C juga berputar.<o:p></o:p></span></p><p><span lang=\"IN\" style=\"font-size:12.0pt;line-height:\r\n107%;font-family:&quot;Times New Roman&quot;,serif;mso-ascii-theme-font:major-bidi;\r\nmso-fareast-font-family:Calibri;mso-fareast-theme-font:minor-latin;mso-hansi-theme-font:\r\nmajor-bidi;mso-bidi-theme-font:major-bidi;mso-ansi-language:IN;mso-fareast-language:\r\nEN-US;mso-bidi-language:AR-SA\">\r\n\r\n\r\n\r\n\r\n\r\n<span lang=\"IN\" style=\"font-size: 12pt; line-height: 107%;\">Bagaimana\r\ngaya pada pegangan A menyebabkan keranjang berputar adalah....</span></span></p>', '<p><span lang=\"IN\" style=\"font-size:12.0pt;line-height:\r\n107%;font-family:&quot;Times New Roman&quot;,serif;mso-ascii-theme-font:major-bidi;\r\nmso-fareast-font-family:Calibri;mso-fareast-theme-font:minor-latin;mso-hansi-theme-font:\r\nmajor-bidi;mso-bidi-theme-font:major-bidi;mso-ansi-language:IN;mso-fareast-language:\r\nEN-US;mso-bidi-language:AR-SA\">gaya pada pegangan A menghasilkan torsi pada\r\ngear B dan karena ukuran gear C lebih kecil maka keranjang berputar lebih cepat</span></p>', '<p><span lang=\"IN\" style=\"font-size:12.0pt;line-height:\r\n107%;font-family:&quot;Times New Roman&quot;,serif;mso-ascii-theme-font:major-bidi;\r\nmso-fareast-font-family:Calibri;mso-fareast-theme-font:minor-latin;mso-hansi-theme-font:\r\nmajor-bidi;mso-bidi-theme-font:major-bidi;mso-ansi-language:IN;mso-fareast-language:\r\nEN-US;mso-bidi-language:AR-SA\">gaya pada pegangan A menghasilkan torsi pada\r\ngear B, dan karena gear C memiliki jumlah gigi berbeda maka putarannya\r\nmeningkat sehingga keranjang berputar lebih cepat</span></p>', '<p><span lang=\"IN\" style=\"font-size:12.0pt;line-height:\r\n107%;font-family:&quot;Times New Roman&quot;,serif;mso-ascii-theme-font:major-bidi;\r\nmso-fareast-font-family:Calibri;mso-fareast-theme-font:minor-latin;mso-hansi-theme-font:\r\nmajor-bidi;mso-bidi-theme-font:major-bidi;mso-ansi-language:IN;mso-fareast-language:\r\nEN-US;mso-bidi-language:AR-SA\">gaya pada pegangan A menghasilkan torsi pada\r\ngear B, dan karena gear C terhubung langsung ke keranjang membuat keranjang\r\nmemperoleh kecepatan sudut yang lebih cepat</span></p>', '<p><span lang=\"IN\" style=\"font-size:12.0pt;line-height:\r\n107%;font-family:&quot;Times New Roman&quot;,serif;mso-ascii-theme-font:major-bidi;\r\nmso-fareast-font-family:Calibri;mso-fareast-theme-font:minor-latin;mso-hansi-theme-font:\r\nmajor-bidi;mso-bidi-theme-font:major-bidi;mso-ansi-language:IN;mso-fareast-language:\r\nEN-US;mso-bidi-language:AR-SA\">gaya pada pegangan A menghasilkan torsi pada\r\ngear B, dan karena gear C memiliki pada rasio gear berbeda maka putaran yang\r\nditransmisikan ke keranjang meningkat menjadi lebih cepat</span></p>', '<p><span lang=\"IN\" style=\"font-size:12.0pt;line-height:\r\n107%;font-family:&quot;Times New Roman&quot;,serif;mso-ascii-theme-font:major-bidi;\r\nmso-fareast-font-family:Calibri;mso-fareast-theme-font:minor-latin;mso-hansi-theme-font:\r\nmajor-bidi;mso-bidi-theme-font:major-bidi;mso-ansi-language:IN;mso-fareast-language:\r\nEN-US;mso-bidi-language:AR-SA\">gaya pada pegangan A menghasilkan torsi pada\r\ngear B, dan karena gear C memiliki ukuran gear lebih besar maka keranjang\r\nberputar dengan kecepatan sudut yang lebih cepat</span></p>', '<p><span lang=\"IN\" style=\"font-size:12.0pt;line-height:\r\n107%;font-family:&quot;Times New Roman&quot;,serif;mso-ascii-theme-font:major-bidi;\r\nmso-fareast-font-family:Calibri;mso-fareast-theme-font:minor-latin;mso-hansi-theme-font:\r\nmajor-bidi;mso-bidi-theme-font:major-bidi;mso-ansi-language:IN;mso-fareast-language:\r\nEN-US;mso-bidi-language:AR-SA\">gaya pada pegangan A menghasilkan torsi pada\r\ngear B, dan karena gear C memiliki ukuran gear lebih besar maka keranjang\r\nberputar dengan kecepatan sudut yang lebih cepat</span></p>', NULL, 'E', -0.390, 0, 1, '2026-05-03 16:46:18', '2026-05-03 16:46:18'),
(377, 'ACTofROD17', 11, NULL, '<p><span lang=\"IN\" style=\"font-size:12.0pt;line-height:\r\n107%;font-family:&quot;Times New Roman&quot;,serif;mso-ascii-theme-font:major-bidi;\r\nmso-fareast-font-family:Calibri;mso-fareast-theme-font:minor-latin;mso-hansi-theme-font:\r\nmajor-bidi;mso-bidi-theme-font:major-bidi;mso-ansi-language:IN;mso-fareast-language:\r\nEN-US;mso-bidi-language:AR-SA\">Gambar 17 menunjukkan sebuah eksperimen untuk\r\nmenentukan momen inersia roda sepeda.</span></p><p><img src=\"https://cd-cat.ct.ws/uploads/editor-images/editor_1777761917_69f67e7da2399.png\" class=\"img-fluid\" style=\"display: block; max-width: 100%; height: 169.615px; margin: 10px 0px; width: 271.69px;\"></p><p class=\"MsoNormal\" align=\"center\" style=\"text-align:center;line-height:150%\"><span lang=\"IN\" style=\"font-size:12.0pt;line-height:150%;font-family:&quot;Times New Roman&quot;,serif;\r\nmso-ascii-theme-font:major-bidi;mso-hansi-theme-font:major-bidi;mso-bidi-theme-font:\r\nmajor-bidi\">Gambar 17. Sepeda terbalik yang pada ujung roda dipasang beban<o:p></o:p></span></p><p><span lang=\"IN\" style=\"font-size:12.0pt;line-height:\r\n107%;font-family:&quot;Times New Roman&quot;,serif;mso-ascii-theme-font:major-bidi;\r\nmso-fareast-font-family:Calibri;mso-fareast-theme-font:minor-latin;mso-hansi-theme-font:\r\nmajor-bidi;mso-bidi-theme-font:major-bidi;mso-ansi-language:IN;mso-fareast-language:\r\nEN-US;mso-bidi-language:AR-SA\">\r\n\r\n<span lang=\"IN\" style=\"font-size: 12pt; line-height: 107%;\">Salah\r\nsatu ujung benang yang kuat diikatkan ke roda. Benang tersebut dililitkan di\r\nsekitar roda, dan beban sebesar 0,2 kg diikatkan pada ujung bebas benang. Roda\r\ndipegang sedemikian rupa sehingga beban berada pada ketinggian 1,5 m di atas\r\nlantai. Dengan mengabaikan gesekan antara poros dan sumbu rotasi, perubahan\r\nenergi yang terjadi mulai dari saat roda dilepaskan hingga beban menyentuh\r\nlantai adalah....</span></span></p>', '<p><span lang=\"IN\" style=\"font-size:11.0pt;line-height:\r\n107%;font-family:&quot;Times New Roman&quot;,serif;mso-ascii-theme-font:major-bidi;\r\nmso-fareast-font-family:Calibri;mso-fareast-theme-font:minor-latin;mso-hansi-theme-font:\r\nmajor-bidi;mso-bidi-theme-font:major-bidi;mso-ansi-language:IN;mso-fareast-language:\r\nEN-US;mso-bidi-language:AR-SA\">energi potensial berubah seluruhnya menjadi\r\nenergi kinetik saat mencapai lantai, sementara roda tetap tidak berputar karena\r\nbenang mencegah rotasi</span></p>', '<p><span lang=\"IN\" style=\"font-size:11.0pt;line-height:\r\n107%;font-family:&quot;Times New Roman&quot;,serif;mso-ascii-theme-font:major-bidi;\r\nmso-fareast-font-family:Calibri;mso-fareast-theme-font:minor-latin;mso-hansi-theme-font:\r\nmajor-bidi;mso-bidi-theme-font:major-bidi;mso-ansi-language:IN;mso-fareast-language:\r\nEN-US;mso-bidi-language:AR-SA\">energi potensial berubah sebagian menjadi energi\r\nkinetik dan sebagian menjadi energi kinetik rotasi roda ketika benang\r\nmengerahkan torsi pada roda</span></p>', '<p><span lang=\"SV\" style=\"font-size:11.0pt;line-height:\r\n107%;font-family:&quot;Times New Roman&quot;,serif;mso-ascii-theme-font:major-bidi;\r\nmso-fareast-font-family:Calibri;mso-fareast-theme-font:minor-latin;mso-hansi-theme-font:\r\nmajor-bidi;mso-bidi-theme-font:major-bidi;mso-ansi-language:SV;mso-fareast-language:\r\nEN-US;mso-bidi-language:AR-SA\">energi potensial berubah sebagian menjadi energi\r\nbunyi karena gesekan udara pada roda, sementara energi kinetik rotasi tidak berubah</span></p>', '<p><span lang=\"IN\" style=\"font-size:11.0pt;line-height:\r\n107%;font-family:&quot;Times New Roman&quot;,serif;mso-ascii-theme-font:major-bidi;\r\nmso-fareast-font-family:Calibri;mso-fareast-theme-font:minor-latin;mso-hansi-theme-font:\r\nmajor-bidi;mso-bidi-theme-font:major-bidi;mso-ansi-language:IN;mso-fareast-language:\r\nEN-US;mso-bidi-language:AR-SA\">energi kinetik roda berubah menjadi energi\r\npotensial sehingga massa turun lebih lambat dari jatuh bebas</span></p>', '<p><span lang=\"SV\" style=\"font-size:11.0pt;line-height:\r\n107%;font-family:&quot;Times New Roman&quot;,serif;mso-ascii-theme-font:major-bidi;\r\nmso-fareast-font-family:Calibri;mso-fareast-theme-font:minor-latin;mso-hansi-theme-font:\r\nmajor-bidi;mso-bidi-theme-font:major-bidi;mso-ansi-language:SV;mso-fareast-language:\r\nEN-US;mso-bidi-language:AR-SA\">energi potensial berubah sepenuhnya menjadi\r\nenergi panas akibat gesekan pada poros roda</span></p>', '<p><span lang=\"IN\" style=\"font-size:11.0pt;line-height:\r\n107%;font-family:&quot;Times New Roman&quot;,serif;mso-ascii-theme-font:major-bidi;\r\nmso-fareast-font-family:Calibri;mso-fareast-theme-font:minor-latin;mso-hansi-theme-font:\r\nmajor-bidi;mso-bidi-theme-font:major-bidi;mso-ansi-language:IN;mso-fareast-language:\r\nEN-US;mso-bidi-language:AR-SA\">energi potensial berubah sebagian menjadi energi\r\nkinetik dan sebagian menjadi energi kinetik rotasi roda ketika benang\r\nmengerahkan torsi pada roda</span></p>', NULL, 'B', 0.180, 0, 1, '2026-05-03 16:46:18', '2026-05-03 16:46:18'),
(378, 'ACTofROD16', 11, NULL, '<p><span lang=\"IN\" style=\"font-size:12.0pt;line-height:\r\n107%;font-family:&quot;Times New Roman&quot;,serif;mso-ascii-theme-font:major-bidi;\r\nmso-fareast-font-family:Calibri;mso-fareast-theme-font:minor-latin;mso-hansi-theme-font:\r\nmajor-bidi;mso-bidi-theme-font:major-bidi;mso-ansi-language:IN;mso-fareast-language:\r\nEN-US;mso-bidi-language:AR-SA\">Gambar 16 menunjukkan dua poros A dan B yang\r\nberputar bebas pada sumbu rotasi yang sama. Poros A&nbsp; berputar searah jarum jam dengan kecepatan\r\nsudut 95 rad/detik dan momen inersia 7,2&nbsp;</span><span lang=\"IN\" style=\"font-size: 12pt; line-height: 17.12px; font-family: &quot;Times New Roman&quot;, serif;\">kg/m</span><span lang=\"IN\" style=\"line-height: 12.84px; font-family: &quot;Times New Roman&quot;, serif; font-size: 12px;\"><sup>2</sup></span><span lang=\"IN\" style=\"font-size: 12pt; line-height: 107%; font-family: &quot;Times New Roman&quot;, serif;\">. Sedangkan poros B\r\nberputar berlawanan arah jarum jam dengan kecepatan sudut 45 rad/detik dan\r\nmomen inersia 11,5 kg/m</span><span lang=\"IN\" style=\"line-height: 107%; font-family: &quot;Times New Roman&quot;, serif; font-size: 12px;\"><sup>2</sup></span><span lang=\"IN\" style=\"font-size: 12pt; line-height: 107%; font-family: &quot;Times New Roman&quot;, serif;\">.</span></p><p><img src=\"https://cd-cat.ct.ws/uploads/editor-images/editor_1777761750_69f67dd6572fd.png\" class=\"img-fluid\" style=\"display: block; max-width: 100%; height: 116.399px; margin: 10px 0px; width: 368.104px;\"></p><p class=\"MsoNormal\" align=\"center\" style=\"text-align:center;line-height:150%\"><span lang=\"IN\" style=\"font-size:12.0pt;line-height:150%;font-family:&quot;Times New Roman&quot;,serif;\r\nmso-ascii-theme-font:major-bidi;mso-hansi-theme-font:major-bidi;mso-bidi-theme-font:\r\nmajor-bidi\">Gambar 16. Dua poros yang berputar bebas pada sumbu rotasi yang\r\nsama</span></p><p class=\"MsoListParagraph\" style=\"margin-